CREATE DATABASE babyshop;
CREATE TABLE users (
  userId INT AUTO_INCREMENT PRIMARY KEY,
  userName VARCHAR(100) NOT NULL,
  email VARCHAR(100) UNIQUE,
  password VARCHAR(255) NOT NULL,
  phone VARCHAR(20) UNIQUE,
  isVerified BOOLEAN DEFAULT FALSE,
  role ENUM('user','admin') DEFAULT 'user',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);
CREATE TABLE addresses (
  addressId INT AUTO_INCREMENT PRIMARY KEY,
  userId INT,
  fullName VARCHAR(100),
  Phone VARCHAR(20),
  province VARCHAR(100),
  district VARCHAR(100),
  detailAddress TEXT,
  note TEXT,
  isDefault BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(userId) ON DELETE CASCADE
);
CREATE TABLE otp_codes (
  id INT AUTO_INCREMENT PRIMARY KEY,
  userId INT,
  otp VARCHAR(10),
created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  expired_at TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(userId)
);
CREATE TABLE categories (
  categoryId INT AUTO_INCREMENT PRIMARY KEY,
  categoryName VARCHAR(100)
);
CREATE TABLE products (
productId INT AUTO_INCREMENT PRIMARY KEY,
productName VARCHAR(255) NOT NULL,
price INT NOT NULL,
description TEXT,
categoryId INT,
status BOOLEAN DEFAULT TRUE,
created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
FOREIGN KEY (categoryId) REFERENCES categories(categoryId)
);
CREATE TABLE product_images (
imageId INT AUTO_INCREMENT PRIMARY KEY,
productId INT,
imageUrl TEXT NOT NULL,
isMain BOOLEAN DEFAULT FALSE,
FOREIGN KEY (productId) REFERENCES products(productId) ON DELETE CASCADE
);
CREATE TABLE discounts (
  discountId INT AUTO_INCREMENT PRIMARY KEY,
  discountCode VARCHAR(100),
  discountValue INT,
  discountType ENUM('percent','fixed'), 
  startDate DATE,
  endDate DATE,
  status BOOLEAN DEFAULT TRUE
);
CREATE TABLE orders (
  orderId INT AUTO_INCREMENT PRIMARY KEY,
  userId INT,
  addressId INT,
  totalAmount INT,
  discountId INT,
  discountAmount INT,
  finalAmount INT,
  paymentMethod ENUM('cod','momo','vnpay'), -- 
  status ENUM('pending','confirmed','shipping','delivered','cancelled'),
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(userId),
  FOREIGN KEY (discountId) REFERENCES discounts(discountId)
);
CREATE TABLE orderdetails (
  orderDetailId INT AUTO_INCREMENT PRIMARY KEY,
  orderId INT,
  productId INT,
  quantity INT,
  price INT,
  size ENUM('S','M','L') DEFAULT 'M',
  FOREIGN KEY (orderId) REFERENCES orders(orderId),
  FOREIGN KEY (productId) REFERENCES products(productId)
);
CREATE TABLE reviews (
  reviewId INT AUTO_INCREMENT PRIMARY KEY,
  userId INT,
  productId INT,
  orderId INT,
  rating INT,
  comment TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(userId),
  FOREIGN KEY (productId) REFERENCES products(productId),
  FOREIGN KEY (orderId) REFERENCES orders(orderId),
  UNIQUE (userId, productId, orderId)
);
CREATE TABLE product_specs (
  specId INT AUTO_INCREMENT PRIMARY KEY,
  productId INT,
  specName VARCHAR(255),
  specValue VARCHAR(255),
  FOREIGN KEY (productId) REFERENCES products(productId)
);
CREATE TABLE product_discounts (
  id INT AUTO_INCREMENT PRIMARY KEY,
  productId INT,
  discountId INT,
  FOREIGN KEY (productId) REFERENCES products(productId),
  FOREIGN KEY (discountId) REFERENCES discounts(discountId)
);




ALTER TABLE otp_codes
ADD isUsed BOOLEAN DEFAULT FALSE;

ALTER TABLE categories ADD icon VARCHAR(255);

// 10 sản phẩm



(2, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Meiji nổi tiếng đến từ Nhật Bản, được sản xuất trên dây chuyền công nghệ hiện đại, tuân thủ các tiêu chuẩn nghiêm ngặt về an toàn thực phẩm dành cho trẻ sơ sinh.'),
(2, 'Thương hiệu', 'Meiji là một trong những thương hiệu sữa hàng đầu tại Nhật Bản với lịch sử lâu đời, được nhiều bà mẹ tin dùng nhờ chất lượng ổn định và thành phần dinh dưỡng phù hợp với thể trạng trẻ em châu Á.'),
(2, 'Khối lượng', 'Trọng lượng tịnh 800g, đóng gói dạng lon thiếc chắc chắn, giúp bảo quản sữa tốt hơn và thuận tiện cho việc sử dụng lâu dài.'),
(2, 'Độ tuổi', 'Dành cho trẻ từ 0 đến 12 tháng tuổi, giai đoạn quan trọng cho sự phát triển toàn diện về thể chất và trí não của bé.'),
(2, 'Thành phần dinh dưỡng', 'Chứa đầy đủ các dưỡng chất thiết yếu như DHA, ARA, protein, chất béo, vitamin và khoáng chất, hỗ trợ phát triển trí não, tăng cường hệ miễn dịch và giúp bé tăng cân khỏe mạnh.'),
(2, 'Công dụng', 'Hỗ trợ hệ tiêu hóa của bé hoạt động tốt hơn, giúp bé hấp thu dinh dưỡng hiệu quả, hạn chế tình trạng táo bón và tăng cường sức đề kháng tự nhiên.'),
(2, 'Hương vị', 'Sữa có vị nhạt, gần giống với sữa mẹ, giúp bé dễ uống và thích nghi nhanh, đặc biệt phù hợp với trẻ sơ sinh đang trong giai đoạn chuyển đổi từ sữa mẹ sang sữa công thức.'),
(2, 'Hướng dẫn sử dụng', 'Pha sữa theo đúng tỷ lệ được hướng dẫn trên bao bì sản phẩm, sử dụng nước đun sôi để nguội khoảng 40–50°C, khuấy đều cho tan hoàn toàn trước khi cho bé sử dụng.'),
(2, 'Bảo quản', 'Bảo quản nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp. Sau khi mở nắp nên sử dụng trong vòng 3–4 tuần để đảm bảo chất lượng sữa tốt nhất.'),
(2, 'Đóng gói', 'Sản phẩm được đóng gói trong lon thiếc kín, có nắp đậy chắc chắn giúp ngăn ngừa vi khuẩn và độ ẩm xâm nhập, đảm bảo an toàn vệ sinh thực phẩm.'),

(3, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Vinamilk – một trong những công ty sữa hàng đầu tại Việt Nam, được sản xuất trên dây chuyền công nghệ hiện đại đạt chuẩn quốc tế.'),
(3, 'Thương hiệu', 'Vinamilk là thương hiệu uy tín với nhiều năm kinh nghiệm trong lĩnh vực dinh dưỡng, được người tiêu dùng Việt Nam tin tưởng lựa chọn.'),
(3, 'Khối lượng', 'Trọng lượng tịnh 900g, đóng gói dạng lon thiếc chắc chắn, tiện lợi cho việc bảo quản và sử dụng lâu dài.'),
(3, 'Độ tuổi', 'Phù hợp cho trẻ từ 0 đến 6 tuổi (tùy theo dòng Optimum Gold cụ thể), hỗ trợ phát triển toàn diện trong giai đoạn đầu đời.'),
(3, 'Thành phần dinh dưỡng', 'Chứa DHA, Lutein, vitamin A, D, C cùng các khoáng chất thiết yếu như canxi, sắt, kẽm giúp hỗ trợ phát triển trí não, thị giác và hệ xương chắc khỏe.'),
(3, 'Công dụng', 'Giúp tăng cường hệ miễn dịch, hỗ trợ tiêu hóa khỏe mạnh, giúp bé phát triển chiều cao và cân nặng một cách toàn diện.'),
(3, 'Hương vị', 'Sữa có vị thơm nhẹ, dễ uống, phù hợp với khẩu vị của trẻ em Việt Nam, giúp bé dễ dàng làm quen và sử dụng hàng ngày.'),
(3, 'Hướng dẫn sử dụng', 'Pha sữa theo đúng hướng dẫn trên bao bì, sử dụng nước ấm khoảng 40–50°C, khuấy đều cho tan hoàn toàn trước khi cho bé uống.'),
(3, 'Bảo quản', 'Để nơi khô ráo, thoáng mát, tránh ánh nắng trực tiếp. Sau khi mở nắp nên sử dụng trong vòng 3–4 tuần để đảm bảo chất lượng tốt nhất.'),
(3, 'Đóng gói', 'Lon thiếc kín, nắp đậy chắc chắn giúp bảo quản sữa tốt, hạn chế độ ẩm và vi khuẩn xâm nhập.'),

(4, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Pampers nổi tiếng toàn cầu của tập đoàn P&G (Procter & Gamble), được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo an toàn cho làn da nhạy cảm của bé.'),
(4, 'Thương hiệu', 'Pampers là thương hiệu tã bỉm hàng đầu thế giới, được nhiều bà mẹ tin dùng nhờ khả năng thấm hút vượt trội và thiết kế thân thiện với làn da trẻ nhỏ.'),
(4, 'Kích cỡ', 'Size M phù hợp cho trẻ có cân nặng từ khoảng 6–11kg, thiết kế ôm vừa vặn giúp bé thoải mái vận động suốt cả ngày.'),
(4, 'Chất liệu', 'Được làm từ các chất liệu mềm mại, thoáng khí, không gây kích ứng da, giúp bảo vệ làn da nhạy cảm của bé một cách tối ưu.'),
(4, 'Công nghệ thấm hút', 'Trang bị lõi thấm hút đa lớp với công nghệ hiện đại, giúp thấm hút nhanh và khóa chất lỏng hiệu quả, giữ cho bề mặt luôn khô ráo.'),
(4, 'Công dụng', 'Giữ cho bé luôn khô thoáng, hạn chế tình trạng hăm tã, giúp bé ngủ ngon hơn và thoải mái vui chơi suốt ngày dài.'),
(4, 'Thiết kế', 'Thiết kế ôm sát cơ thể với thun co giãn linh hoạt, chống tràn hiệu quả, đồng thời có vạch báo đầy tiện lợi giúp mẹ dễ dàng thay tã đúng lúc.'),
(4, 'Hướng dẫn sử dụng', 'Mặc tã vừa vặn cho bé, kiểm tra và thay tã thường xuyên (3–4 tiếng/lần hoặc khi đầy) để đảm bảo vệ sinh và tránh hăm da.'),
