INSERT INTO product_specs (productId, specName, specValue) VALUES
(1, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Pigeon nổi tiếng đến từ Nhật Bản, được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo an toàn cho trẻ sơ sinh và trẻ nhỏ.'),
(1, 'Chất liệu', 'Bình được làm từ nhựa PPSU cao cấp, có độ bền cao, chịu nhiệt tốt lên đến 180°C, không chứa BPA độc hại, an toàn tuyệt đối cho sức khỏe của bé khi sử dụng lâu dài.'),
(1, 'Dung tích', 'Dung tích 240ml phù hợp cho nhu cầu ăn uống của trẻ sơ sinh và trẻ nhỏ, giúp mẹ dễ dàng kiểm soát lượng sữa mỗi lần cho bé bú.'),
(1, 'Độ tuổi', 'Phù hợp cho trẻ từ 0 đến 3 tuổi, đặc biệt thiết kế núm ti mềm mại mô phỏng ti mẹ, giúp bé dễ dàng làm quen và bú tự nhiên hơn.'),
(1, 'Hướng dẫn sử dụng', 'Trước khi sử dụng cần tiệt trùng bình sữa và núm ti bằng nước sôi hoặc máy tiệt trùng chuyên dụng. Sau khi dùng nên rửa sạch bằng dung dịch rửa bình và bảo quản nơi khô ráo, tránh vi khuẩn.'),
(1, 'Thiết kế', 'Thiết kế thân bình thon gọn, dễ cầm nắm, có vạch chia dung tích rõ ràng giúp mẹ dễ dàng theo dõi lượng sữa. Nắp đậy kín giúp đảm bảo vệ sinh khi di chuyển.'),
(1, 'Núm ti', 'Núm ti silicon siêu mềm, đàn hồi tốt, thiết kế chống sặc, chống đầy hơi hiệu quả, hỗ trợ bé bú thoải mái và hạn chế tình trạng nuốt khí.'),
(1, 'Độ an toàn', 'Sản phẩm đã được kiểm định nghiêm ngặt, không chứa các chất độc hại như BPA, đảm bảo an toàn tuyệt đối cho trẻ nhỏ trong quá trình sử dụng.'),
