INSERT INTO product_specs (productId, specName, specValue) VALUES
(26, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Microlife nổi tiếng của Thụy Sĩ, chuyên về thiết bị y tế gia đình chất lượng cao.'),
(26, 'Công nghệ', 'Ứng dụng công nghệ cảm biến nhiệt hiện đại giúp đo nhanh và chính xác trong thời gian ngắn.'),
(26, 'Công dụng', 'Dùng để đo thân nhiệt cho trẻ em và người lớn, giúp phát hiện sớm các dấu hiệu sốt.'),
(26, 'Thời gian đo', 'Thời gian đo nhanh chỉ khoảng 10–20 giây, cho kết quả chính xác cao.'),
(26, 'Thiết kế', 'Thiết kế nhỏ gọn, dễ sử dụng, màn hình hiển thị rõ ràng, dễ đọc kết quả.'),
(26, 'Hướng dẫn sử dụng', 'Đặt đầu đo vào nách hoặc miệng, chờ tín hiệu báo hoàn tất và đọc kết quả trên màn hình.'),
(27, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Omron Nhật Bản, được tin dùng trong lĩnh vực thiết bị y tế.'),
(27, 'Công nghệ', 'Công nghệ Intellisense tự động bơm hơi vòng bít, cho kết quả nhanh và chính xác.'),
(27, 'Công dụng', 'Giúp theo dõi huyết áp tại nhà, hỗ trợ phát hiện sớm các vấn đề về tim mạch.'),
(27, 'Thiết kế', 'Thiết kế nhỏ gọn, màn hình LCD lớn, hiển thị rõ ràng các chỉ số.'),
(27, 'Đối tượng sử dụng', 'Phù hợp cho người lớn, người cao tuổi và gia đình cần theo dõi sức khỏe thường xuyên.'),
(27, 'Hướng dẫn sử dụng', 'Quấn vòng bít vào bắp tay, nhấn nút và chờ máy hiển thị kết quả.'),
(28, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Chicco đến từ Ý, đạt tiêu chuẩn an toàn châu Âu.'),
(28, 'Chất liệu', 'Nhựa cao cấp không chứa BPA, an toàn tuyệt đối cho trẻ nhỏ.'),
(28, 'Công dụng', 'Giúp làm sạch dịch nhầy trong mũi, hỗ trợ bé dễ thở hơn khi bị nghẹt mũi.'),
(28, 'Thiết kế', 'Đầu hút mềm mại, không gây tổn thương niêm mạc mũi của bé.'),
(28, 'Đối tượng sử dụng', 'Dành cho trẻ sơ sinh và trẻ nhỏ.'),
(28, 'Hướng dẫn sử dụng', 'Đưa nhẹ đầu hút vào mũi và hút dịch nhầy một cách nhẹ nhàng.'),
(29, 'Xuất xứ', 'Sản phẩm nhập khẩu từ Pháp, sử dụng nước biển tự nhiên tinh khiết.'),
(29, 'Thành phần', '100% nước biển tự nhiên, giàu khoáng chất có lợi cho niêm mạc mũi.'),
(29, 'Công dụng', 'Giúp làm sạch mũi, giảm nghẹt mũi và phòng ngừa các bệnh về đường hô hấp.'),
(29, 'Đối tượng sử dụng', 'Phù hợp cho trẻ sơ sinh, trẻ nhỏ và người lớn.'),
(29, 'Hướng dẫn sử dụng', 'Xịt trực tiếp vào mũi 1–2 lần mỗi bên, ngày 2–3 lần.'),
(29, 'Bảo quản', 'Bảo quản nơi khô ráo, tránh ánh nắng trực tiếp.'),
(30, 'Xuất xứ', 'Thương hiệu Beurer nổi tiếng đến từ Đức, chuyên sản xuất thiết bị chăm sóc sức khỏe.'),
(30, 'Công nghệ', 'Sử dụng công nghệ hồng ngoại không tiếp xúc, đảm bảo an toàn và vệ sinh.'),
(30, 'Công dụng', 'Đo nhiệt độ cơ thể nhanh chóng mà không cần tiếp xúc trực tiếp.'),
(30, 'Thời gian đo', 'Kết quả hiển thị chỉ trong 1–2 giây.'),
(30, 'Thiết kế', 'Thiết kế hiện đại, màn hình hiển thị rõ ràng, dễ sử dụng.'),
(30, 'Hướng dẫn sử dụng', 'Đưa nhiệt kế gần trán và bấm nút đo.'),
(31, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Omron Nhật Bản, đạt tiêu chuẩn thiết bị y tế.'),
(31, 'Công nghệ', 'Công nghệ khí dung giúp chuyển thuốc thành dạng sương mịn.'),
(31, 'Công dụng', 'Hỗ trợ điều trị các bệnh về đường hô hấp như viêm mũi, viêm phế quản.'),
(31, 'Đối tượng sử dụng', 'Dành cho cả trẻ em và người lớn.'),
(31, 'Hướng dẫn sử dụng', 'Sử dụng theo chỉ định của bác sĩ và hướng dẫn đi kèm sản phẩm.'),
(31, 'Bảo quản', 'Vệ sinh thiết bị sau mỗi lần sử dụng.'),
(32, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Kobayashi Nhật Bản.'),
(32, 'Công dụng', 'Giúp hạ nhiệt và làm mát cơ thể khi bị sốt.'),
(32, 'Thành phần', 'Gel làm mát an toàn, không gây kích ứng da.'),
(32, 'Đối tượng sử dụng', 'Dành cho trẻ em và người lớn.'),
(32, 'Hướng dẫn sử dụng', 'Dán trực tiếp lên trán hoặc vùng cần làm mát.'),
(32, 'Thời gian sử dụng', 'Hiệu quả làm mát kéo dài từ 6–8 giờ.'),
(33, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Philips Avent nổi tiếng toàn cầu.'),
(33, 'Công nghệ', 'Tiệt trùng bằng hơi nước tiêu diệt đến 99.9% vi khuẩn.'),
(33, 'Công dụng', 'Giữ vệ sinh bình sữa và dụng cụ ăn uống cho bé.'),
(33, 'Thiết kế', 'Dung tích lớn, có thể tiệt trùng nhiều bình cùng lúc.'),
(33, 'Hướng dẫn sử dụng', 'Cho nước vào và bật máy theo hướng dẫn.'),
(33, 'Bảo quản', 'Vệ sinh máy thường xuyên để đảm bảo hiệu quả.'),
(34, 'Xuất xứ', 'Thương hiệu Fatzbaby chuyên sản phẩm mẹ và bé.'),
(34, 'Công nghệ', 'Gia nhiệt đều giúp giữ nguyên dưỡng chất trong sữa.'),
(34, 'Công dụng', 'Hâm nóng sữa và thức ăn cho bé nhanh chóng.'),
(34, 'Thiết kế', 'Nhỏ gọn, dễ sử dụng, phù hợp cho gia đình.'),
(34, 'Hướng dẫn sử dụng', 'Cho bình vào máy và chọn chế độ phù hợp.'),
(34, 'Bảo quản', 'Giữ máy sạch sẽ và khô ráo.'),
(35, 'Xuất xứ', 'Thương hiệu Xiaomi nổi tiếng về thiết bị thông minh.'),
(35, 'Công nghệ', 'Cảm biến nhiệt độ và độ ẩm chính xác cao.'),
(35, 'Công dụng', 'Giúp theo dõi môi trường phòng để chăm sóc bé tốt hơn.'),
(35, 'Thiết kế', 'Thiết kế nhỏ gọn, hiện đại, dễ đặt trong phòng.'),
(35, 'Hướng dẫn sử dụng', 'Đặt thiết bị trong phòng và theo dõi thông số hiển thị.'),
(35, 'Bảo quản', 'Tránh nơi ẩm ướt và va đập mạnh.');
