('Đồ chơi học số và đếm hình', 130000, 'Giúp bé làm quen với các con số và kỹ năng đếm cơ bản', 7, TRUE),
('Bộ đồ chơi nấu ăn cho bé', 220000, 'Giúp bé nhập vai và phát triển kỹ năng giao tiếp, sáng tạo', 7, TRUE),
('Đồ chơi xe điều khiển từ xa', 320000, 'Xe điều khiển giúp bé giải trí và phát triển khả năng phản xạ', 7, TRUE),
('Bảng học toán thông minh cho bé', 140000, 'Giúp bé học phép tính cơ bản một cách trực quan và sinh động', 7, TRUE),
('Đồ chơi xếp hình nam châm', 260000, 'Bộ đồ chơi sáng tạo với các mảnh ghép nam châm an toàn, dễ sử dụng', 7, TRUE);
INSERT INTO product_specs (productId, specName, specValue) VALUES
(36, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu LEGO nổi tiếng đến từ Đan Mạch, được sản xuất theo tiêu chuẩn chất lượng quốc tế, đảm bảo an toàn cho trẻ nhỏ.'),
(36, 'Thương hiệu', 'LEGO là thương hiệu đồ chơi hàng đầu thế giới, nổi bật với các bộ xếp hình sáng tạo giúp phát triển trí tuệ.'),
(36, 'Loại sản phẩm', 'Đồ chơi xếp hình với nhiều mảnh ghép đa dạng, cho phép trẻ tự do sáng tạo các mô hình theo trí tưởng tượng.'),
(36, 'Độ tuổi', 'Phù hợp cho trẻ từ 4 tuổi trở lên, giúp phát triển kỹ năng vận động tinh và tư duy logic.'),
(36, 'Chất liệu', 'Được làm từ nhựa ABS cao cấp, không chứa chất độc hại, đảm bảo an toàn khi trẻ sử dụng trong thời gian dài.'),
(36, 'Công dụng', 'Giúp trẻ phát triển trí tưởng tượng, khả năng sáng tạo, tư duy logic và kỹ năng giải quyết vấn đề.'),
(36, 'Số lượng chi tiết', 'Bộ sản phẩm bao gồm nhiều mảnh ghép với kích thước và màu sắc khác nhau, tạo sự đa dạng khi lắp ráp.'),
(36, 'Hướng dẫn sử dụng', 'Trẻ có thể lắp ráp theo hướng dẫn hoặc tự sáng tạo các mô hình theo ý thích.'),
(36, 'Bảo quản', 'Bảo quản nơi khô ráo, tránh nhiệt độ cao và ánh nắng trực tiếp để giữ độ bền và màu sắc.'),
(37, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho trẻ em, phù hợp sử dụng trong gia đình và trường học.'),
(37, 'Loại sản phẩm', 'Bảng học chữ cái tiếng Việt giúp bé làm quen với bảng chữ cái một cách trực quan và sinh động.'),
(37, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–6 tuổi trong giai đoạn bắt đầu học chữ.'),
(37, 'Chất liệu', 'Chất liệu nhựa hoặc gỗ cao cấp, không chứa chất độc hại, an toàn cho trẻ nhỏ.'),
(37, 'Công dụng', 'Giúp bé nhận biết chữ cái, phát triển khả năng ngôn ngữ và trí nhớ.'),
(37, 'Thiết kế', 'Thiết kế nhiều màu sắc sinh động, hình ảnh minh họa giúp bé dễ ghi nhớ và hứng thú học tập.'),
(37, 'Phương pháp học', 'Kết hợp vừa học vừa chơi giúp trẻ tiếp thu kiến thức một cách tự nhiên và hiệu quả.'),
(37, 'Hướng dẫn sử dụng', 'Cha mẹ hướng dẫn bé học từng chữ cái và ghép vần cơ bản.'),
(37, 'Bảo quản', 'Giữ sạch và bảo quản nơi khô ráo sau khi sử dụng.'),
(38, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo độ bền và an toàn khi sử dụng cho trẻ nhỏ.'),
(38, 'Loại sản phẩm', 'Đồ chơi lắp ráp robot thông minh giúp trẻ phát triển tư duy kỹ thuật và sáng tạo.'),
(38, 'Độ tuổi', 'Phù hợp cho trẻ từ 5 tuổi trở lên, đặc biệt yêu thích khám phá và sáng tạo.'),
(38, 'Chất liệu', 'Nhựa cao cấp chắc chắn, không chứa chất độc hại, an toàn cho trẻ em.'),
(38, 'Công dụng', 'Giúp trẻ rèn luyện khả năng tư duy logic, kỹ năng giải quyết vấn đề và phát triển trí tưởng tượng.'),
(38, 'Tính năng', 'Có thể lắp ráp thành nhiều mô hình robot khác nhau, tăng tính linh hoạt và sáng tạo.'),
(38, 'Kỹ năng phát triển', 'Hỗ trợ phát triển kỹ năng vận động tinh, khả năng phối hợp tay và mắt.'),
(38, 'Hướng dẫn sử dụng', 'Lắp ráp theo sách hướng dẫn đi kèm hoặc sáng tạo theo ý tưởng riêng.'),
(38, 'Bảo quản', 'Tránh va đập mạnh, bảo quản nơi khô ráo để tăng độ bền sản phẩm.'),
(39, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho trẻ em, phù hợp sử dụng trong gia đình và môi trường học tập.'),
(39, 'Loại sản phẩm', 'Bảng vẽ điện tử LCD giúp bé tập vẽ, viết và sáng tạo mà không cần sử dụng giấy hay bút mực.'),
(39, 'Độ tuổi', 'Phù hợp cho trẻ từ 3 tuổi trở lên, hỗ trợ phát triển tư duy sáng tạo.'),
(39, 'Chất liệu', 'Nhựa ABS cao cấp, màn hình LCD an toàn cho mắt, không phát ra ánh sáng xanh gây hại.'),
(39, 'Công dụng', 'Giúp bé luyện tập viết chữ, vẽ tranh và phát triển trí tưởng tượng một cách tự nhiên.'),
(39, 'Tính năng', 'Có nút xóa nhanh, cho phép xóa toàn bộ nội dung chỉ với một lần nhấn, tiết kiệm thời gian và tiện lợi.'),
(39, 'Thiết kế', 'Thiết kế mỏng nhẹ, dễ mang theo, phù hợp cho bé sử dụng ở nhà hoặc khi đi học.'),
(39, 'Hướng dẫn sử dụng', 'Dùng bút đi kèm để viết hoặc vẽ lên màn hình, nhấn nút xóa để làm mới bảng.'),
(39, 'Bảo quản', 'Tránh va đập mạnh và không để tiếp xúc với nước để đảm bảo độ bền sản phẩm.'),
(40, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo an toàn cho trẻ em khi sử dụng.'),
(40, 'Loại sản phẩm', 'Đồ chơi ghép hình gỗ 3D giúp bé rèn luyện tư duy logic và khả năng quan sát.'),
(40, 'Độ tuổi', 'Phù hợp cho trẻ từ 3–8 tuổi, hỗ trợ phát triển kỹ năng nhận biết hình khối.'),
(40, 'Chất liệu', 'Gỗ tự nhiên được xử lý nhẵn mịn, không góc cạnh sắc nhọn, an toàn cho trẻ nhỏ.'),
(40, 'Công dụng', 'Giúp phát triển khả năng tư duy không gian, nhận biết hình dạng và rèn luyện sự khéo léo.'),
(40, 'Thiết kế', 'Các mảnh ghép được thiết kế chính xác, màu sắc bắt mắt giúp thu hút sự chú ý của trẻ.'),
(40, 'Số lượng chi tiết', 'Gồm nhiều mảnh ghép với hình dạng khác nhau, giúp bé có nhiều cách lắp ráp sáng tạo.'),
(40, 'Hướng dẫn sử dụng', 'Lắp ráp các mảnh ghép theo hình mẫu hoặc sáng tạo theo ý tưởng riêng của bé.'),
(40, 'Bảo quản', 'Giữ sản phẩm khô ráo, tránh tiếp xúc với nước để đảm bảo độ bền của gỗ.'),
(41, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn dành cho đồ chơi giáo dục trẻ em.'),
(41, 'Loại sản phẩm', 'Đồ chơi học số và đếm hình giúp bé làm quen với các con số và phép đếm cơ bản.'),
(41, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–6 tuổi trong giai đoạn phát triển nhận thức ban đầu.'),
(41, 'Chất liệu', 'Nhựa hoặc gỗ cao cấp, không chứa chất độc hại, an toàn cho trẻ.'),
(41, 'Công dụng', 'Giúp bé nhận biết số, học đếm và phát triển tư duy toán học cơ bản.'),
(41, 'Thiết kế', 'Thiết kế nhiều màu sắc sinh động, hình ảnh trực quan giúp bé dễ tiếp thu kiến thức.'),
(41, 'Phương pháp học', 'Kết hợp giữa học và chơi giúp trẻ tiếp thu kiến thức một cách tự nhiên và hiệu quả.'),
(41, 'Hướng dẫn sử dụng', 'Cha mẹ hướng dẫn bé nhận biết số và thực hành đếm qua các hình minh họa.'),
(41, 'Bảo quản', 'Giữ sạch và bảo quản nơi khô ráo sau khi sử dụng.'),
(42, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ chơi an toàn cho trẻ em.'),
(42, 'Loại sản phẩm', 'Bộ đồ chơi nấu ăn giúp bé nhập vai và phát triển kỹ năng sống.'),
(42, 'Độ tuổi', 'Phù hợp cho trẻ từ 3 tuổi trở lên, đặc biệt yêu thích hoạt động nhập vai.'),
(42, 'Chất liệu', 'Nhựa cao cấp, không chứa BPA, an toàn cho trẻ nhỏ khi sử dụng.'),
(42, 'Công dụng', 'Giúp bé phát triển kỹ năng giao tiếp, sáng tạo và học hỏi các hoạt động trong cuộc sống hàng ngày.'),
(42, 'Thiết kế', 'Bộ sản phẩm gồm nhiều dụng cụ nấu ăn mini như nồi, chảo, muỗng… với màu sắc bắt mắt.'),
(42, 'Kỹ năng phát triển', 'Hỗ trợ phát triển kỹ năng xã hội, khả năng phối hợp tay mắt và tư duy sáng tạo.'),
(42, 'Hướng dẫn sử dụng', 'Bé có thể chơi nhập vai nấu ăn cùng bạn bè hoặc gia đình.'),
(42, 'Bảo quản', 'Tránh va đập mạnh và bảo quản nơi khô ráo.'), 
(43, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo độ bền và an toàn khi sử dụng cho trẻ em.'),
(43, 'Loại sản phẩm', 'Đồ chơi xe điều khiển từ xa giúp bé giải trí và rèn luyện khả năng phản xạ nhanh.'),
(43, 'Độ tuổi', 'Phù hợp cho trẻ từ 5 tuổi trở lên, đặc biệt yêu thích các trò chơi vận động và điều khiển.'),
(43, 'Chất liệu', 'Nhựa ABS cao cấp kết hợp linh kiện điện tử an toàn, không chứa chất độc hại.'),
(43, 'Công dụng', 'Giúp bé phát triển khả năng phản xạ, phối hợp tay – mắt và tăng cường sự tập trung.'),
(43, 'Tính năng', 'Điều khiển từ xa với nhiều hướng di chuyển linh hoạt như tiến, lùi, rẽ trái, rẽ phải.'),
(43, 'Nguồn điện', 'Sử dụng pin sạc hoặc pin rời tùy theo từng mẫu sản phẩm.'),
(43, 'Thiết kế', 'Thiết kế chắc chắn, màu sắc bắt mắt, bánh xe linh hoạt giúp di chuyển trên nhiều bề mặt.'),
(43, 'Hướng dẫn sử dụng', 'Lắp pin vào xe và tay điều khiển, sau đó sử dụng remote để điều khiển xe.'),
(43, 'Bảo quản', 'Tránh va đập mạnh, không để tiếp xúc với nước để đảm bảo độ bền của sản phẩm.'),
(44, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho đồ chơi giáo dục trẻ em, phù hợp sử dụng tại nhà và trường học.'),
(44, 'Loại sản phẩm', 'Bảng học toán thông minh giúp bé làm quen với các phép tính cơ bản một cách trực quan.'),
(44, 'Độ tuổi', 'Phù hợp cho trẻ từ 3–7 tuổi trong giai đoạn phát triển tư duy toán học.'),
(44, 'Chất liệu', 'Nhựa hoặc gỗ cao cấp, không chứa chất độc hại, an toàn cho trẻ nhỏ.'),
(44, 'Công dụng', 'Giúp bé nhận biết số, học phép cộng trừ đơn giản và phát triển tư duy logic.'),
(44, 'Thiết kế', 'Thiết kế nhiều màu sắc sinh động, kết hợp hình ảnh minh họa giúp bé dễ hiểu và hứng thú học tập.'),
(44, 'Phương pháp học', 'Kết hợp giữa học và chơi giúp trẻ tiếp thu kiến thức nhanh chóng và hiệu quả.'),
(44, 'Kỹ năng phát triển', 'Phát triển tư duy toán học, khả năng ghi nhớ và kỹ năng giải quyết vấn đề.'),
(44, 'Hướng dẫn sử dụng', 'Cha mẹ hướng dẫn bé thực hành các phép tính cơ bản thông qua bảng học.'),
(44, 'Bảo quản', 'Giữ sạch và bảo quản nơi khô ráo sau khi sử dụng.'),
(45, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn chất lượng cao, đảm bảo an toàn cho trẻ em khi sử dụng.'),
(45, 'Loại sản phẩm', 'Đồ chơi xếp hình nam châm giúp bé phát triển khả năng sáng tạo và tư duy không gian.'),
(45, 'Độ tuổi', 'Phù hợp cho trẻ từ 3 tuổi trở lên, đặc biệt thích hợp cho hoạt động học tập và giải trí.'),
(45, 'Chất liệu', 'Nhựa cao cấp kết hợp nam châm an toàn, không chứa chất độc hại.'),
(45, 'Công dụng', 'Giúp trẻ phát triển trí tưởng tượng, tư duy logic và khả năng sáng tạo thông qua việc lắp ghép.'),
(45, 'Tính năng', 'Các mảnh ghép có nam châm giúp dễ dàng kết nối với nhau, tạo nhiều hình dạng khác nhau.'),
(45, 'Thiết kế', 'Màu sắc tươi sáng, hình dạng đa dạng giúp thu hút sự chú ý của trẻ nhỏ.'),
(45, 'Kỹ năng phát triển', 'Rèn luyện khả năng phối hợp tay – mắt, tư duy không gian và sự khéo léo.'),
(45, 'Hướng dẫn sử dụng', 'Lắp ghép các mảnh theo hướng dẫn hoặc sáng tạo theo ý tưởng riêng của bé.'),
(45, 'Bảo quản', 'Tránh va đập mạnh và bảo quản nơi khô ráo để giữ độ bền sản phẩm.');
