INSERT INTO products (productName, price, description, categoryId, status)
VALUES
('Ghế ngồi ô tô Animo OneFit Isofix 360', 1970000, 'Ghế ngồi ô tô cho bé xoay 360 độ, an toàn và tiện lợi khi di chuyển', 1, TRUE),
('Bàn chải đánh răng có vòng chắn cho bé Mamamy', 77000, 'Bàn chải mềm có vòng chắn an toàn, phù hợp cho bé tập đánh răng', 1, TRUE),
('Ghế ngồi ô tô Animo OneFit Pro Isofix 360', 3050000, 'Ghế ô tô cao cấp với hệ thống Isofix chắc chắn, bảo vệ bé tối đa', 1, TRUE),
('Sữa bầu Friso Mum Gold 400g', 220000, 'Sữa dinh dưỡng dành cho mẹ bầu, bổ sung vitamin và khoáng chất cần thiết', 1, TRUE),
('Bộ gặm nướu xúc xắc 6 món cho bé', 150000, 'Đồ chơi gặm nướu giúp bé giảm đau khi mọc răng và phát triển giác quan', 1, TRUE),
('Khăn tắm trẻ em cao cấp Poemy 60x110cm', 120000, 'Khăn mềm mại, thấm hút tốt, an toàn cho làn da nhạy cảm của bé', 1, TRUE),
