('Máy hâm sữa Fatzbaby FB3003SL', 550000, 'Máy hâm sữa tiện lợi giúp giữ nhiệt và làm nóng sữa nhanh chóng', 1, TRUE);
INSERT INTO product_specs (productId, specName, specValue) VALUES
(46, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Animo, được sản xuất theo tiêu chuẩn an toàn châu Âu (ECE R44/04), đảm bảo chất lượng và độ an toàn cao khi sử dụng cho trẻ nhỏ trong quá trình di chuyển.'),
(46, 'Loại sản phẩm', 'Ghế ngồi ô tô cao cấp dành cho trẻ em, tích hợp hệ thống Isofix hiện đại giúp cố định chắc chắn vào xe.'),
(46, 'Độ tuổi', 'Phù hợp cho trẻ từ sơ sinh đến khoảng 12 tuổi (0–36kg), sử dụng lâu dài theo từng giai đoạn phát triển.'),
(46, 'Chất liệu', 'Khung thép chịu lực kết hợp nhựa ABS cao cấp và lớp đệm mút dày, tạo cảm giác êm ái và an toàn.'),
(46, 'Công nghệ', 'Hệ thống Isofix giúp cố định ghế chắc chắn, giảm rung lắc và tăng độ ổn định khi xe di chuyển.'),
(46, 'Tính năng', 'Xoay 360 độ giúp bố mẹ dễ dàng đặt bé vào ghế và thay đổi hướng ngồi linh hoạt.'),
(46, 'An toàn', 'Trang bị dây đai 5 điểm và hệ thống bảo vệ va chạm hai bên, giúp bảo vệ bé tối đa khi có sự cố.'),
(46, 'Thiết kế', 'Thiết kế ôm sát cơ thể, có thể điều chỉnh nhiều tư thế ngồi và nằm phù hợp với từng độ tuổi.'),
(46, 'Hướng dẫn sử dụng', 'Lắp đặt bằng hệ thống Isofix, cố định chắc chắn và điều chỉnh dây đai phù hợp với bé.'),
(46, 'Bảo quản', 'Vệ sinh định kỳ, tránh ánh nắng trực tiếp và không để sản phẩm ở nơi ẩm ướt.'),
(47, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Mamamy Việt Nam, được sản xuất theo tiêu chuẩn an toàn dành cho trẻ nhỏ.'),
(47, 'Loại sản phẩm', 'Bàn chải đánh răng dành cho bé có vòng chắn an toàn, giúp hạn chế việc đưa bàn chải quá sâu.'),
(47, 'Độ tuổi', 'Phù hợp cho trẻ từ 6 tháng đến 3 tuổi trong giai đoạn mọc răng sữa.'),
(47, 'Chất liệu', 'Lông bàn chải siêu mềm, tay cầm bằng nhựa cao cấp không chứa BPA, an toàn tuyệt đối.'),
(47, 'Công dụng', 'Giúp làm sạch răng và nướu, hình thành thói quen vệ sinh răng miệng cho bé từ sớm.'),
(47, 'Thiết kế', 'Thiết kế nhỏ gọn, vừa tay bé, có vòng chắn chống nuốt sâu đảm bảo an toàn.'),
(47, 'An toàn', 'Không gây tổn thương nướu, phù hợp với răng sữa và nướu nhạy cảm của trẻ.'),
(47, 'Hướng dẫn sử dụng', 'Làm ướt bàn chải, sử dụng nhẹ nhàng và có thể kết hợp với kem đánh răng cho trẻ em.'),
(47, 'Bảo quản', 'Rửa sạch sau khi sử dụng và để nơi khô ráo, thoáng mát.'),
(49, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Friso Hà Lan, nổi tiếng toàn cầu với các dòng sữa dinh dưỡng chất lượng cao.'),
(49, 'Loại sản phẩm', 'Sữa bột dinh dưỡng dành cho phụ nữ mang thai và cho con bú.'),
(49, 'Thành phần', 'Giàu DHA, canxi, sắt, axit folic và các vitamin thiết yếu giúp hỗ trợ sức khỏe mẹ và bé.'),
(49, 'Công dụng', 'Giúp bổ sung dinh dưỡng cho mẹ, hỗ trợ sự phát triển trí não và thể chất của thai nhi.'),
(49, 'Đối tượng sử dụng', 'Phù hợp cho phụ nữ mang thai và sau sinh cần bổ sung dinh dưỡng.'),
(49, 'Hương vị', 'Hương cam nhẹ, dễ uống, không gây ngán khi sử dụng lâu dài.'),
(49, 'Hướng dẫn sử dụng', 'Pha sữa với nước ấm theo tỷ lệ hướng dẫn trên bao bì, khuấy đều trước khi uống.'),
(49, 'Bảo quản', 'Đậy kín nắp sau khi mở, bảo quản nơi khô ráo và tránh ánh nắng trực tiếp.'),
(50, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn dành cho trẻ sơ sinh và trẻ nhỏ.'),
(50, 'Loại sản phẩm', 'Đồ chơi gặm nướu kết hợp xúc xắc giúp bé vừa chơi vừa giảm đau khi mọc răng.'),
(50, 'Độ tuổi', 'Phù hợp cho trẻ từ 3 tháng tuổi trở lên.'),
(50, 'Chất liệu', 'Silicone thực phẩm cao cấp, không chứa BPA, an toàn khi bé ngậm.'),
(50, 'Công dụng', 'Giúp giảm đau nướu, kích thích giác quan và phát triển khả năng cầm nắm.'),
(50, 'Thiết kế', 'Thiết kế nhiều hình dạng và màu sắc sinh động, dễ cầm nắm.'),
(50, 'An toàn', 'Không chứa chất độc hại, đảm bảo an toàn tuyệt đối cho trẻ nhỏ.'),
(50, 'Hướng dẫn sử dụng', 'Rửa sạch trước khi sử dụng và có thể tiệt trùng bằng nước ấm.'),
(50, 'Bảo quản', 'Bảo quản nơi khô ráo, tránh bụi bẩn và ánh nắng trực tiếp.'),
(51, 'Xuất xứ', 'Sản phẩm thuộc dòng khăn cao cấp Poemy, được sản xuất theo tiêu chuẩn dệt may an toàn cho trẻ em, đảm bảo không chứa hóa chất độc hại và thân thiện với làn da nhạy cảm của trẻ sơ sinh.'),
(51, 'Loại sản phẩm', 'Khăn tắm cao cấp dành riêng cho trẻ sơ sinh và trẻ nhỏ, phù hợp sử dụng hàng ngày trong quá trình chăm sóc bé.'),
(51, 'Chất liệu', '100% cotton tự nhiên cao cấp, sợi bông mềm mịn, có khả năng thấm hút nước nhanh gấp nhiều lần so với khăn thông thường.'),
(51, 'Kích thước', 'Kích thước tiêu chuẩn 60x110cm, đủ rộng để quấn toàn thân bé, giữ ấm hiệu quả sau khi tắm.'),
(51, 'Công dụng', 'Giúp lau khô cơ thể nhanh chóng, giữ ấm cho bé và hạn chế tình trạng nhiễm lạnh sau khi tắm.'),
(51, 'Đặc điểm nổi bật', 'Khăn có độ mềm mại cao, không xơ cứng sau nhiều lần giặt, không gây kích ứng da và phù hợp với làn da nhạy cảm.'),
(51, 'Thiết kế', 'Thiết kế đơn giản, màu sắc nhẹ nhàng, đường may chắc chắn, không bị bung sợi trong quá trình sử dụng lâu dài.'),
(51, 'Độ an toàn', 'Không chứa chất tẩy trắng mạnh, không gây dị ứng, đạt tiêu chuẩn an toàn cho trẻ sơ sinh.'),
(51, 'Hướng dẫn sử dụng', 'Nên giặt sạch trước khi sử dụng lần đầu, sử dụng để lau khô hoặc quấn bé sau khi tắm.'),
(51, 'Bảo quản', 'Giặt bằng nước ấm, phơi nơi khô ráo, tránh môi trường ẩm mốc để đảm bảo độ bền và vệ sinh.'),
(52, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Kita, được sản xuất theo tiêu chuẩn an toàn thực phẩm quốc tế, đảm bảo chất lượng và độ bền cao.'),
(52, 'Loại sản phẩm', 'Bình nước thể thao đa năng phù hợp cho cả mẹ và bé sử dụng trong sinh hoạt hàng ngày.'),
(52, 'Dung tích', 'Dung tích 700ml, đáp ứng nhu cầu bổ sung nước trong ngày cho người dùng.'),
(52, 'Chất liệu', 'Nhựa Tritan cao cấp, không chứa BPA, không gây ảnh hưởng đến sức khỏe khi sử dụng lâu dài.'),
(52, 'Công dụng', 'Dùng để đựng nước, nước trái cây hoặc các loại đồ uống khác khi đi học, đi làm hoặc tập thể thao.'),
(52, 'Tính năng nổi bật', 'Chống rò rỉ tuyệt đối, nắp kín chắc chắn, có thể mang theo trong balo mà không lo đổ nước.'),
(52, 'Thiết kế', 'Thiết kế hiện đại, thân bình trong suốt giúp dễ dàng kiểm soát lượng nước còn lại, dễ cầm nắm.'),
(52, 'Độ bền', 'Chịu va đập tốt, không dễ nứt vỡ trong quá trình sử dụng hàng ngày.'),
(52, 'Hướng dẫn sử dụng', 'Rửa sạch trước khi sử dụng, không nên đựng nước quá nóng để tránh biến dạng sản phẩm.'),
(52, 'Bảo quản', 'Bảo quản nơi khô ráo, tránh ánh nắng trực tiếp và nhiệt độ cao.'),
(53, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Thinksport nổi tiếng của Mỹ, chuyên cung cấp các sản phẩm an toàn cho sức khỏe người dùng.'),
(53, 'Loại sản phẩm', 'Bình nước thể thao cao cấp phù hợp cho cả người lớn và trẻ em.'),
(53, 'Dung tích', 'Dung tích 700ml, đáp ứng nhu cầu sử dụng nước trong ngày.'),
(53, 'Chất liệu', 'Chất liệu cao cấp không chứa BPA, không chứa hóa chất độc hại, đảm bảo an toàn tuyệt đối.'),
(53, 'Công dụng', 'Giúp duy trì thói quen uống đủ nước mỗi ngày, hỗ trợ sức khỏe và sinh hoạt.'),
(53, 'Tính năng nổi bật', 'Khả năng chống rò rỉ tốt, nắp đóng kín chắc chắn, dễ dàng mang theo khi di chuyển.'),
(53, 'Thiết kế', 'Thiết kế thể thao năng động, phù hợp cho nhiều đối tượng sử dụng từ học sinh đến người lớn.'),
(53, 'Độ bền', 'Chịu lực tốt, chống va đập hiệu quả, sử dụng lâu dài mà không bị biến dạng.'),
(53, 'Hướng dẫn sử dụng', 'Rửa sạch trước khi sử dụng lần đầu, vệ sinh thường xuyên để đảm bảo an toàn.'),
(53, 'Bảo quản', 'Tránh ánh nắng trực tiếp và nhiệt độ cao để giữ độ bền sản phẩm.'),
(54, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn quốc tế về đồ chơi trẻ em, đảm bảo an toàn tuyệt đối cho trẻ sơ sinh.'),
(54, 'Loại sản phẩm', 'Đồ chơi treo nôi phát nhạc giúp kích thích giác quan và hỗ trợ phát triển toàn diện cho bé.'),
(54, 'Độ tuổi', 'Phù hợp cho trẻ từ 0 tháng tuổi trở lên, đặc biệt trong giai đoạn sơ sinh.'),
(54, 'Chất liệu', 'Nhựa cao cấp kết hợp vải mềm, không chứa chất độc hại, an toàn khi tiếp xúc với trẻ nhỏ.'),
(54, 'Công dụng', 'Giúp bé thư giãn, dễ ngủ hơn, đồng thời phát triển thính giác và khả năng nhận biết âm thanh.'),
(54, 'Tính năng', 'Phát nhạc nhẹ nhàng, có thể xoay hoặc chuyển động để thu hút sự chú ý của bé.'),
(54, 'Thiết kế', 'Thiết kế nhiều hình thú ngộ nghĩnh với màu sắc sinh động, kích thích thị giác của trẻ.'),
(54, 'Kỹ năng phát triển', 'Hỗ trợ phát triển thính giác, thị giác và khả năng tập trung của trẻ sơ sinh.'),
(54, 'Hướng dẫn sử dụng', 'Gắn chắc chắn lên nôi hoặc cũi, bật chế độ phát nhạc khi cần thiết.'),
(54, 'Bảo quản', 'Giữ sạch, tránh va đập mạnh và không để tiếp xúc với nước.'),
(55, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Fatzbaby, nổi tiếng với các thiết bị chăm sóc mẹ và bé tiện lợi.'),
(55, 'Loại sản phẩm', 'Máy hâm sữa đa năng giúp giữ nhiệt và làm nóng sữa nhanh chóng cho bé.'),
(55, 'Công nghệ', 'Công nghệ gia nhiệt đều giúp giữ nguyên dưỡng chất trong sữa, tránh hiện tượng quá nhiệt.'),
(55, 'Công dụng', 'Hâm nóng sữa, giữ nhiệt nước và hỗ trợ pha sữa nhanh chóng, đặc biệt tiện lợi vào ban đêm.'),
(55, 'Dung tích', 'Phù hợp với nhiều loại bình sữa khác nhau trên thị trường.'),
(55, 'Tính năng', 'Có nhiều chế độ hâm nóng, giữ nhiệt và rã đông thực phẩm cho bé.'),
(55, 'Thiết kế', 'Thiết kế nhỏ gọn, dễ sử dụng, phù hợp với không gian gia đình hiện đại.'),
(55, 'Độ an toàn', 'Tự động ngắt khi quá nhiệt, đảm bảo an toàn khi sử dụng lâu dài.'),
(55, 'Hướng dẫn sử dụng', 'Cho nước vào máy, đặt bình sữa và chọn chế độ phù hợp.'),
(55, 'Bảo quản', 'Vệ sinh định kỳ, giữ khô ráo và tránh để nước tràn vào bộ phận điện.');
