INSERT INTO products (productName, price, description, categoryId, status)
VALUES
('Kem chống rạn da Bio Oil 125ml', 320000, 'Giúp ngăn ngừa và cải thiện vết rạn da cho mẹ bầu trong thai kỳ', 10, TRUE),
('Kem dưỡng ẩm cho bé Cetaphil Baby 400ml', 280000, 'Dưỡng ẩm dịu nhẹ, phù hợp với làn da nhạy cảm của trẻ sơ sinh', 10, TRUE),
('Sữa tắm gội toàn thân Mustela 500ml', 350000, 'Làm sạch nhẹ nhàng, không gây kích ứng cho da và tóc của bé', 10, TRUE),
('Dầu dưỡng da cho mẹ Palmer’s Cocoa Butter', 250000, 'Dưỡng ẩm sâu và hỗ trợ giảm rạn da trong và sau thai kỳ', 10, TRUE),
('Kem chống nắng cho mẹ Anessa Mild Milk', 420000, 'Bảo vệ da khỏi tia UV, phù hợp cho phụ nữ mang thai và sau sinh', 10, TRUE),
('Phấn rôm Johnson Baby 200g', 90000, 'Giúp giữ da bé luôn khô thoáng, ngăn ngừa hăm da', 10, TRUE),
('Kem hăm tã Sudocrem 125g', 180000, 'Giúp giảm hăm tã và bảo vệ làn da nhạy cảm của bé', 10, TRUE),
('Nước hoa hồng dịu nhẹ cho mẹ Simple', 160000, 'Cân bằng độ ẩm, làm dịu da nhạy cảm cho mẹ sau sinh', 10, TRUE),
('Sữa dưỡng thể cho mẹ Vaseline Healthy Bright', 140000, 'Giúp dưỡng ẩm và làm sáng da an toàn cho mẹ', 10, TRUE),
('Gel rửa tay khô cho mẹ và bé Dettol', 75000, 'Diệt khuẩn hiệu quả, tiện lợi khi ra ngoài', 10, TRUE);
INSERT INTO product_specs (productId, specName, specValue) VALUES
(56, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Bio-Oil nổi tiếng toàn cầu, được sản xuất theo tiêu chuẩn chất lượng cao và được nhiều chuyên gia da liễu khuyên dùng.'),
(56, 'Loại sản phẩm', 'Dầu dưỡng da chuyên dụng giúp cải thiện và ngăn ngừa tình trạng rạn da trong và sau thai kỳ.'),
(56, 'Thành phần', 'Chứa vitamin A, vitamin E, chiết xuất từ các loại dầu thực vật như dầu hoa cúc, dầu oải hương giúp nuôi dưỡng da.'),
(56, 'Công dụng', 'Giúp làm mờ vết rạn da, sẹo, cải thiện sắc tố da và tăng độ đàn hồi cho da.'),
(56, 'Loại da phù hợp', 'Phù hợp với mọi loại da, đặc biệt là da khô và da nhạy cảm của phụ nữ mang thai.'),
(56, 'Kết cấu', 'Dạng dầu nhẹ, thẩm thấu nhanh, không gây nhờn rít.'),
(56, 'Hướng dẫn sử dụng', 'Thoa một lượng vừa đủ lên vùng da cần chăm sóc 2 lần mỗi ngày, massage nhẹ nhàng để đạt hiệu quả tốt nhất.'),
(56, 'Độ an toàn', 'Đã được kiểm nghiệm da liễu, an toàn cho phụ nữ mang thai khi sử dụng đúng cách.'),
(56, 'Bảo quản', 'Để nơi khô ráo, tránh ánh nắng trực tiếp và nhiệt độ cao.'),
(57, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Cetaphil nổi tiếng của Canada, chuyên về chăm sóc da nhạy cảm.'),
(57, 'Loại sản phẩm', 'Kem dưỡng ẩm dành riêng cho làn da nhạy cảm của trẻ sơ sinh và trẻ nhỏ.'),
(57, 'Thành phần', 'Chứa glycerin, dầu hạnh nhân và các dưỡng chất tự nhiên giúp cấp ẩm sâu cho da.'),
(57, 'Công dụng', 'Giúp giữ ẩm, làm mềm da và bảo vệ làn da khỏi tình trạng khô ráp.'),
(57, 'Loại da phù hợp', 'Phù hợp cho da nhạy cảm, da khô và da dễ kích ứng của trẻ nhỏ.'),
(57, 'Kết cấu', 'Dạng kem mịn, dễ thẩm thấu, không gây bết dính.'),
(57, 'Độ an toàn', 'Không chứa paraben, không gây kích ứng, đã được kiểm nghiệm da liễu.'),
(57, 'Hướng dẫn sử dụng', 'Thoa lên da bé sau khi tắm hoặc khi da bị khô.'),
(57, 'Bảo quản', 'Đậy kín nắp sau khi sử dụng, tránh ánh nắng trực tiếp.'),
(58, 'Xuất xứ', 'Thương hiệu Mustela đến từ Pháp, nổi tiếng với các sản phẩm chăm sóc da cho trẻ em.'),
(58, 'Loại sản phẩm', 'Sữa tắm gội toàn thân 2 trong 1 dành cho trẻ sơ sinh và trẻ nhỏ.'),
(58, 'Thành phần', 'Chứa chiết xuất từ quả bơ và các thành phần tự nhiên giúp bảo vệ làn da bé.'),
(58, 'Công dụng', 'Làm sạch nhẹ nhàng, giữ ẩm và bảo vệ da bé khỏi khô ráp.'),
(58, 'Loại da phù hợp', 'Phù hợp với mọi loại da, đặc biệt là da nhạy cảm của trẻ sơ sinh.'),
(58, 'Độ an toàn', 'Không chứa xà phòng, không paraben, không gây cay mắt.'),
(58, 'Hướng dẫn sử dụng', 'Lấy một lượng nhỏ, tạo bọt và tắm cho bé, sau đó rửa sạch.'),
(58, 'Bảo quản', 'Đậy kín sau khi sử dụng, bảo quản nơi thoáng mát.'),
(59, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Palmer’s nổi tiếng của Mỹ, chuyên về chăm sóc da cho mẹ bầu.'),
(59, 'Loại sản phẩm', 'Kem dưỡng và dầu dưỡng giúp giảm rạn da trong thai kỳ.'),
(59, 'Thành phần', 'Chứa bơ cacao, vitamin E và collagen giúp tăng độ đàn hồi cho da.'),
(59, 'Công dụng', 'Giúp ngăn ngừa và cải thiện tình trạng rạn da, dưỡng ẩm sâu cho da.'),
(59, 'Loại da phù hợp', 'Phù hợp với da khô và da bị rạn trong thai kỳ.'),
(59, 'Kết cấu', 'Dạng kem đặc hoặc dầu, thẩm thấu tốt và giữ ẩm lâu.'),
(59, 'Hướng dẫn sử dụng', 'Thoa đều lên vùng bụng, đùi và ngực 2 lần mỗi ngày.'),
(59, 'Độ an toàn', 'An toàn cho phụ nữ mang thai khi sử dụng đúng cách.'),
(59, 'Bảo quản', 'Để nơi khô ráo, tránh nhiệt độ cao.'),
(60, 'Xuất xứ', 'Thương hiệu Anessa thuộc tập đoàn Shiseido Nhật Bản, nổi tiếng về sản phẩm chống nắng.'),
(60, 'Loại sản phẩm', 'Kem chống nắng dịu nhẹ dành cho mẹ, đặc biệt phù hợp cho phụ nữ mang thai.'),
(60, 'Thành phần', 'Chứa các hoạt chất chống tia UV cùng thành phần dưỡng ẩm cho da.'),
(60, 'Công dụng', 'Bảo vệ da khỏi tia UVA/UVB, ngăn ngừa sạm nám và lão hóa da.'),
(60, 'Loại da phù hợp', 'Phù hợp với da nhạy cảm và da của phụ nữ mang thai.'),
(60, 'Chỉ số chống nắng', 'SPF cao giúp bảo vệ da hiệu quả dưới ánh nắng mặt trời.'),
(60, 'Kết cấu', 'Dạng sữa lỏng, thẩm thấu nhanh, không gây nhờn rít.'),
(60, 'Hướng dẫn sử dụng', 'Thoa trước khi ra nắng 15–20 phút, bôi lại sau mỗi 2–3 giờ.'),
(60, 'Bảo quản', 'Tránh ánh nắng trực tiếp, đậy kín nắp sau khi sử dụng.'),
(61, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Johnson’s Baby của Mỹ, nổi tiếng toàn cầu với các dòng sản phẩm chăm sóc trẻ em an toàn và dịu nhẹ.'),
(61, 'Loại sản phẩm', 'Phấn rôm dành cho trẻ sơ sinh và trẻ nhỏ giúp giữ da luôn khô thoáng.'),
(61, 'Thành phần', 'Chứa bột talc tinh khiết kết hợp các thành phần an toàn, không gây kích ứng da.'),
(61, 'Công dụng', 'Giúp hút ẩm, giảm ma sát trên da, ngăn ngừa hăm tã và giữ cho da bé luôn khô ráo.'),
(61, 'Loại da phù hợp', 'Phù hợp với làn da nhạy cảm của trẻ sơ sinh và trẻ nhỏ.'),
(61, 'Kết cấu', 'Dạng bột mịn, nhẹ, dễ dàng thoa đều trên da.'),
(61, 'Độ an toàn', 'Đã được kiểm nghiệm da liễu, không gây kích ứng khi sử dụng đúng cách.'),
(61, 'Hướng dẫn sử dụng', 'Lấy một lượng nhỏ ra tay rồi thoa nhẹ nhàng lên vùng da cần sử dụng.'),
(61, 'Bảo quản', 'Đậy kín nắp sau khi sử dụng, tránh để nơi ẩm ướt.'),
(62, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Sudocrem đến từ Anh, được tin dùng rộng rãi trong chăm sóc da trẻ em.'),
(62, 'Loại sản phẩm', 'Kem chống hăm tã chuyên dụng dành cho trẻ sơ sinh và trẻ nhỏ.'),
(62, 'Thành phần', 'Chứa kẽm oxit và các thành phần giúp làm dịu da, giảm viêm và bảo vệ da.'),
(62, 'Công dụng', 'Giúp làm dịu và giảm tình trạng hăm tã, tạo lớp bảo vệ da khỏi tác động của độ ẩm và vi khuẩn.'),
(62, 'Loại da phù hợp', 'Phù hợp với làn da nhạy cảm, da dễ bị kích ứng của trẻ nhỏ.'),
(62, 'Kết cấu', 'Dạng kem đặc, dễ thoa và bám tốt trên da.'),
(62, 'Độ an toàn', 'Không gây kích ứng, phù hợp sử dụng hàng ngày cho bé.'),
(62, 'Hướng dẫn sử dụng', 'Thoa một lớp mỏng lên vùng da bị hăm sau khi vệ sinh sạch sẽ.'),
(62, 'Bảo quản', 'Để nơi khô ráo, tránh ánh nắng trực tiếp.'),
(63, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Simple của Anh, nổi tiếng với các sản phẩm dịu nhẹ cho da nhạy cảm.'),
(63, 'Loại sản phẩm', 'Nước hoa hồng (toner) giúp cân bằng độ ẩm và làm dịu da.'),
(63, 'Thành phần', 'Chứa vitamin B5, nước tinh khiết và các thành phần không gây kích ứng.'),
(63, 'Công dụng', 'Giúp làm sạch sâu, cân bằng độ pH và làm dịu da sau khi rửa mặt.'),
(63, 'Loại da phù hợp', 'Phù hợp với da nhạy cảm, da khô và da dễ kích ứng, đặc biệt phù hợp cho mẹ sau sinh.'),
(63, 'Kết cấu', 'Dạng nước lỏng, thẩm thấu nhanh, không gây nhờn rít.'),
(63, 'Độ an toàn', 'Không chứa cồn, không hương liệu, không paraben.'),
(63, 'Hướng dẫn sử dụng', 'Dùng bông tẩy trang thấm toner và lau nhẹ nhàng lên da.'),
(63, 'Bảo quản', 'Đậy kín sau khi sử dụng, tránh ánh nắng trực tiếp.'),
(64, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Vaseline nổi tiếng toàn cầu, được tin dùng trong chăm sóc da.'),
(64, 'Loại sản phẩm', 'Sữa dưỡng thể giúp cấp ẩm và làm sáng da.'),
(64, 'Thành phần', 'Chứa vitamin B3, glycerin và các dưỡng chất giúp nuôi dưỡng da.'),
(64, 'Công dụng', 'Giúp dưỡng ẩm sâu, cải thiện tình trạng da khô và làm sáng da tự nhiên.'),
(64, 'Loại da phù hợp', 'Phù hợp với mọi loại da, đặc biệt là da khô và thiếu ẩm.'),
(64, 'Kết cấu', 'Dạng lotion nhẹ, dễ thẩm thấu, không gây nhờn dính.'),
(64, 'Độ an toàn', 'Không gây kích ứng, phù hợp cho phụ nữ sau sinh.'),
(64, 'Hướng dẫn sử dụng', 'Thoa đều lên cơ thể sau khi tắm hoặc khi da khô.'),
(64, 'Bảo quản', 'Để nơi khô ráo, tránh ánh nắng trực tiếp.'),
(65, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Dettol nổi tiếng về các sản phẩm diệt khuẩn.'),
(65, 'Loại sản phẩm', 'Gel rửa tay khô diệt khuẩn không cần dùng nước.'),
(65, 'Thành phần', 'Chứa cồn và các hoạt chất kháng khuẩn giúp tiêu diệt vi khuẩn nhanh chóng.'),
(65, 'Công dụng', 'Giúp làm sạch tay, diệt khuẩn hiệu quả và tiện lợi khi ra ngoài.'),
(65, 'Loại da phù hợp', 'Phù hợp cho mọi loại da, kể cả da nhạy cảm.'),
(65, 'Kết cấu', 'Dạng gel trong suốt, khô nhanh, không gây nhờn.'),
(65, 'Độ an toàn', 'Đã được kiểm nghiệm, an toàn khi sử dụng thường xuyên.'),
(65, 'Hướng dẫn sử dụng', 'Lấy một lượng gel vừa đủ, xoa đều lên tay cho đến khi khô.'),
(65, 'Bảo quản', 'Đậy kín nắp, tránh nhiệt độ cao và lửa.');
