INSERT INTO product_specs (productId, specName, specValue) VALUES
(76, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho đồ trang trí sự kiện, phù hợp sử dụng trong gia đình và trường học.'),
(76, 'Loại sản phẩm', 'Bộ phụ kiện trang trí sinh nhật đầy đủ gồm bóng bay, banner, dây treo và nến.'),
(76, 'Chất liệu', 'Nhựa, giấy cao cấp và cao su an toàn, không chứa chất độc hại.'),
(76, 'Công dụng', 'Giúp trang trí không gian tiệc sinh nhật trở nên sinh động, tạo không khí vui tươi cho bé.'),
(76, 'Thành phần bộ sản phẩm', 'Bao gồm nhiều phụ kiện như bóng bay nhiều màu, dây treo, chữ banner chúc mừng và nến sinh nhật.'),
(76, 'Độ tuổi phù hợp', 'Phù hợp cho trẻ em trong các dịp sinh nhật hoặc sự kiện gia đình.'),
(76, 'Thiết kế', 'Màu sắc bắt mắt, thiết kế dễ thương, phù hợp với nhiều chủ đề sinh nhật.'),
(76, 'Hướng dẫn sử dụng', 'Lắp ráp và treo các phụ kiện theo ý muốn để trang trí không gian tiệc.'),
(76, 'Bảo quản', 'Giữ nơi khô ráo, tránh ánh nắng trực tiếp để tái sử dụng.'),
(77, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho đồ dùng tiệc sinh nhật.'),
(77, 'Loại sản phẩm', 'Nến trang trí bánh sinh nhật hình số đại diện cho độ tuổi.'),
(77, 'Chất liệu', 'Sáp cao cấp, không chứa hóa chất độc hại, an toàn khi đốt.'),
(77, 'Công dụng', 'Dùng để trang trí bánh sinh nhật, tạo điểm nhấn và ghi dấu mốc tuổi của bé.'),
(77, 'Thiết kế', 'Nhiều màu sắc tươi sáng, hình dạng số rõ ràng, dễ nhìn.'),
(77, 'Độ an toàn', 'Cháy ổn định, ít khói, không gây ảnh hưởng đến sức khỏe.'),
(77, 'Hướng dẫn sử dụng', 'Cắm nến lên bánh và thắp sáng trước khi tổ chức tiệc.'),
(77, 'Bảo quản', 'Để nơi khô ráo, tránh nhiệt độ cao làm biến dạng nến.'),
(78, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn cho đồ chơi và trang trí sự kiện.'),
(78, 'Loại sản phẩm', 'Bóng bay trang trí tiệc sinh nhật và sự kiện.'),
(78, 'Chất liệu', 'Cao su latex cao cấp, có độ co giãn tốt và an toàn cho người sử dụng.'),
(78, 'Công dụng', 'Trang trí không gian tiệc, tạo không khí vui vẻ và sinh động.'),
(78, 'Thiết kế', 'Nhiều màu sắc đa dạng, có thể kết hợp để tạo thành các cụm trang trí đẹp mắt.'),
(78, 'Độ bền', 'Bóng có độ đàn hồi tốt, ít bị nổ khi bơm đúng cách.'),
(78, 'Hướng dẫn sử dụng', 'Bơm khí vào bóng và treo hoặc kết hợp trang trí theo ý thích.'),
(78, 'Bảo quản', 'Tránh vật sắc nhọn và nhiệt độ cao.'),
(79, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn thiết bị điện dân dụng an toàn.'),
(79, 'Loại sản phẩm', 'Đèn LED dây trang trí dùng cho tiệc và không gian phòng.'),
(79, 'Chất liệu', 'Dây đồng kết hợp bóng LED nhỏ, lớp vỏ cách điện an toàn.'),
(79, 'Công dụng', 'Tạo ánh sáng trang trí ấm áp, giúp không gian trở nên lung linh và nổi bật.'),
(79, 'Công suất', 'Tiết kiệm điện năng, hoạt động bền bỉ trong thời gian dài.'),
(79, 'Thiết kế', 'Dây dài linh hoạt, dễ uốn cong và trang trí theo nhiều kiểu khác nhau.'),
(79, 'Hướng dẫn sử dụng', 'Kết nối nguồn điện hoặc pin và bố trí theo không gian cần trang trí.'),
(79, 'Bảo quản', 'Tránh tiếp xúc với nước và môi trường ẩm.'),
(80, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn in ấn chất lượng cao, đảm bảo độ bền và tính thẩm mỹ.'),
(80, 'Loại sản phẩm', 'Thiệp chúc mừng dùng trong các dịp sinh nhật và sự kiện đặc biệt.'),
(80, 'Chất liệu', 'Giấy cứng cao cấp, bề mặt in sắc nét, không phai màu.'),
(80, 'Công dụng', 'Dùng để gửi lời chúc ý nghĩa đến người thân, bạn bè trong các dịp đặc biệt.'),
(80, 'Thiết kế', 'Thiết kế đa dạng, màu sắc tươi sáng, phù hợp với nhiều đối tượng.'),
(80, 'Kích thước', 'Kích thước vừa phải, dễ ghi nội dung và mang theo.'),
(80, 'Hướng dẫn sử dụng', 'Viết lời chúc và gửi kèm quà tặng hoặc trao trực tiếp.'),
(80, 'Bảo quản', 'Giữ nơi khô ráo, tránh gập hoặc ẩm mốc.'),
(81, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đóng gói quà tặng cao cấp, đảm bảo tính thẩm mỹ và độ bền khi sử dụng.'),
(81, 'Loại sản phẩm', 'Hộp quà tặng dùng trong các dịp sinh nhật, lễ kỷ niệm và sự kiện đặc biệt.'),
(81, 'Chất liệu', 'Giấy cứng cao cấp kết hợp lớp phủ bóng hoặc mờ, giúp tăng độ sang trọng.'),
(81, 'Công dụng', 'Dùng để đựng quà tặng, giúp món quà trở nên đẹp mắt và ý nghĩa hơn.'),
(81, 'Thiết kế', 'Thiết kế hiện đại, màu sắc đa dạng, phù hợp với nhiều đối tượng và dịp khác nhau.'),
(81, 'Kích thước', 'Có nhiều kích thước khác nhau, phù hợp với nhiều loại quà tặng.'),
(81, 'Độ bền', 'Cứng cáp, chịu lực tốt, không bị biến dạng khi sử dụng.'),
(81, 'Hướng dẫn sử dụng', 'Đặt quà vào hộp và trang trí thêm ruy băng hoặc thiệp nếu cần.'),
(81, 'Bảo quản', 'Giữ nơi khô ráo, tránh ẩm mốc để tái sử dụng.'),
(82, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn thiết bị điện tử gia dụng, đảm bảo độ chính xác và độ bền cao.'),
(82, 'Loại sản phẩm', 'Đồng hồ báo thức để bàn dành cho trẻ em và gia đình.'),
(82, 'Chất liệu', 'Nhựa ABS cao cấp kết hợp linh kiện điện tử chất lượng cao.'),
(82, 'Công dụng', 'Giúp bé và gia đình quản lý thời gian, thức dậy đúng giờ và hình thành thói quen sinh hoạt tốt.'),
(82, 'Thiết kế', 'Thiết kế dễ thương, màu sắc sinh động phù hợp với trẻ nhỏ.'),
(82, 'Tính năng', 'Có chức năng báo thức, hiển thị giờ rõ ràng, dễ sử dụng.'),
(82, 'Nguồn điện', 'Sử dụng pin hoặc nguồn điện tùy theo mẫu.'),
(82, 'Hướng dẫn sử dụng', 'Cài đặt giờ và báo thức theo nhu cầu sử dụng.'),
(82, 'Bảo quản', 'Tránh va đập mạnh và không để nơi ẩm ướt.'),
(83, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ gia dụng, đảm bảo độ chính xác và tuổi thọ cao.'),
(83, 'Loại sản phẩm', 'Đồng hồ treo tường dùng để xem giờ và trang trí không gian.'),
(83, 'Chất liệu', 'Nhựa hoặc gỗ cao cấp kết hợp mặt kính trong suốt.'),
(83, 'Công dụng', 'Giúp theo dõi thời gian và tạo điểm nhấn trang trí cho phòng bé hoặc phòng khách.'),
(83, 'Thiết kế', 'Thiết kế dễ thương, màu sắc hài hòa, phù hợp với không gian gia đình.'),
(83, 'Độ chính xác', 'Máy chạy êm, độ chính xác cao, ít sai số.'),
(83, 'Nguồn điện', 'Sử dụng pin AA tiện lợi.'),
(83, 'Hướng dẫn sử dụng', 'Treo lên tường và lắp pin để sử dụng.'),
(83, 'Bảo quản', 'Tránh ánh nắng trực tiếp và môi trường ẩm.'),
(84, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn in ấn chất lượng cao, đảm bảo độ bền và tính thẩm mỹ.'),
(84, 'Loại sản phẩm', 'Lịch để bàn giúp theo dõi ngày tháng và ghi chú sự kiện.'),
(84, 'Chất liệu', 'Giấy cao cấp, bìa cứng chắc chắn, dễ sử dụng.'),
(84, 'Công dụng', 'Giúp ghi nhớ các sự kiện quan trọng, sắp xếp công việc và quản lý thời gian hiệu quả.'),
(84, 'Thiết kế', 'Thiết kế đơn giản, tiện dụng, phù hợp với bàn học và bàn làm việc.'),
(84, 'Kích thước', 'Kích thước nhỏ gọn, dễ đặt trên bàn.'),
(84, 'Tính năng', 'Có thể ghi chú trực tiếp trên từng ngày.'),
(84, 'Hướng dẫn sử dụng', 'Lật từng trang theo ngày và ghi chú khi cần thiết.'),
(84, 'Bảo quản', 'Giữ nơi khô ráo, tránh nước.'),
(85, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ dùng học tập, an toàn cho trẻ em.'),
(85, 'Loại sản phẩm', 'Bảng kế hoạch tuần giúp bé học cách quản lý thời gian và công việc.'),
(85, 'Chất liệu', 'Nhựa hoặc bảng viết có thể xóa, bền và dễ sử dụng.'),
(85, 'Công dụng', 'Giúp bé lập kế hoạch học tập, sinh hoạt và phát triển thói quen tổ chức công việc.'),
(85, 'Thiết kế', 'Thiết kế nhiều màu sắc, chia theo ngày trong tuần rõ ràng.'),
(85, 'Tính năng', 'Có thể viết và xóa nhiều lần, tiện lợi cho việc sử dụng lâu dài.'),
(85, 'Kỹ năng phát triển', 'Giúp trẻ phát triển kỹ năng quản lý thời gian và tính tự giác.'),
(85, 'Hướng dẫn sử dụng', 'Viết kế hoạch hàng tuần bằng bút chuyên dụng và lau khi cần thay đổi.'),
(85, 'Bảo quản', 'Giữ sạch bề mặt và tránh va đập mạnh.');
