INSERT INTO product_specs (productId, specName, specValue) VALUES
(86, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Hipp nổi tiếng của Đức, đạt tiêu chuẩn hữu cơ châu Âu, đảm bảo an toàn và chất lượng cho trẻ nhỏ.'),
(86, 'Loại sản phẩm', 'Bột ăn dặm hữu cơ dành cho trẻ trong giai đoạn bắt đầu ăn dặm.'),
(86, 'Độ tuổi', 'Phù hợp cho trẻ từ 6 tháng tuổi trở lên.'),
(86, 'Thành phần', 'Chiết xuất từ rau củ hữu cơ tự nhiên, không chứa chất bảo quản, không phẩm màu.'),
(86, 'Công dụng', 'Giúp bé làm quen với thực phẩm, hỗ trợ tiêu hóa và cung cấp dinh dưỡng cần thiết cho sự phát triển.'),
(86, 'Hương vị', 'Vị rau củ tự nhiên, dễ ăn, phù hợp khẩu vị của trẻ nhỏ.'),
(86, 'Hướng dẫn sử dụng', 'Pha bột với nước ấm khoảng 40–50°C, khuấy đều trước khi cho bé ăn.'),
(86, 'Bảo quản', 'Đậy kín sau khi mở, bảo quản nơi khô ráo.'),
(87, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Vinamilk Việt Nam, được sản xuất theo tiêu chuẩn dinh dưỡng hiện đại.'),
(87, 'Loại sản phẩm', 'Bột ăn dặm dinh dưỡng dành cho trẻ nhỏ.'),
(87, 'Độ tuổi', 'Phù hợp cho trẻ từ 6 tháng tuổi trở lên.'),
(87, 'Thành phần', 'Chứa vitamin A, D, canxi, sắt và các dưỡng chất cần thiết cho sự phát triển.'),
(87, 'Công dụng', 'Giúp bé phát triển toàn diện về thể chất và trí não, hỗ trợ tăng cân.'),
(87, 'Hương vị', 'Vị ngọt nhẹ, dễ ăn, phù hợp với trẻ nhỏ.'),
(87, 'Hướng dẫn sử dụng', 'Pha với nước ấm theo tỷ lệ hướng dẫn trên bao bì.'),
(87, 'Bảo quản', 'Đóng kín nắp, tránh ẩm mốc.'),
