INSERT INTO product_specs (productId, specName, specValue) VALUES
(96, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Zaracos, được sản xuất theo tiêu chuẩn an toàn quốc tế cho trẻ em.'),
(96, 'Loại sản phẩm', 'Xe đẩy em bé đa năng, phù hợp cho việc di chuyển hàng ngày.'),
(96, 'Độ tuổi', 'Phù hợp cho trẻ từ sơ sinh đến 3 tuổi.'),
(96, 'Tải trọng', 'Chịu tải tối đa khoảng 15–20kg.'),
(96, 'Chất liệu', 'Khung thép chắc chắn kết hợp vải cao cấp, thoáng khí và an toàn cho da bé.'),
(96, 'Tính năng', 'Có thể gấp gọn, điều chỉnh nhiều tư thế nằm/ngồi, mái che chống nắng.'),
(96, 'An toàn', 'Trang bị dây đai 5 điểm và hệ thống phanh bánh xe chắc chắn.'),
(96, 'Thiết kế', 'Thiết kế hiện đại, bánh xe linh hoạt giúp di chuyển dễ dàng.'),
(96, 'Hướng dẫn sử dụng', 'Mở xe, cố định khóa và đặt bé vào, điều chỉnh tư thế phù hợp.'),
(96, 'Bảo quản', 'Giữ sạch, tránh ẩm và vệ sinh định kỳ.'),
(97, 'Xuất xứ', 'Sản phẩm thuộc thương hiệu Seebaby, được sản xuất theo tiêu chuẩn an toàn cho trẻ nhỏ.'),
(97, 'Loại sản phẩm', 'Xe đẩy du lịch gọn nhẹ dành cho bé.'),
(97, 'Độ tuổi', 'Phù hợp cho trẻ từ 6 tháng đến 3 tuổi.'),
(97, 'Tải trọng', 'Chịu tải tối đa khoảng 15kg.'),
(97, 'Chất liệu', 'Khung nhôm nhẹ, vải cao cấp dễ vệ sinh.'),
(97, 'Tính năng', 'Gấp gọn nhanh chóng, dễ mang theo khi đi du lịch hoặc dạo phố.'),
(97, 'An toàn', 'Có dây đai an toàn và phanh bánh xe chắc chắn.'),
(97, 'Thiết kế', 'Thiết kế nhỏ gọn, thời trang, phù hợp di chuyển nhiều.'),
(97, 'Hướng dẫn sử dụng', 'Gấp/mở theo cơ chế khóa, sử dụng đơn giản.'),
(97, 'Bảo quản', 'Tránh va đập mạnh, giữ nơi khô ráo.'),
(98, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn đồ chơi trẻ em.'),
(98, 'Loại sản phẩm', 'Xe chòi chân giúp bé phát triển vận động.'),
(98, 'Độ tuổi', 'Phù hợp cho trẻ từ 1–3 tuổi.'),
(98, 'Chất liệu', 'Nhựa cao cấp, không chứa chất độc hại.'),
(98, 'Công dụng', 'Giúp bé tập đi, rèn luyện khả năng vận động và giữ thăng bằng.'),
(98, 'Tính năng', 'Có tích hợp nhạc và âm thanh giúp bé thích thú khi chơi.'),
(98, 'Thiết kế', 'Màu sắc sinh động, hình dáng dễ thương.'),
(98, 'Độ an toàn', 'Thiết kế bo tròn, không góc cạnh sắc nhọn.'),
