(99, 'Tính năng', 'Điều chỉnh độ cao, có bàn đồ chơi phía trước.'),
(99, 'An toàn', 'Có hệ thống chống lật và bánh xe chắc chắn.'),
(99, 'Thiết kế', 'Thiết kế chắc chắn, dễ di chuyển.'),
(99, 'Hướng dẫn sử dụng', 'Điều chỉnh độ cao phù hợp và cho bé ngồi tập đi.'),
(99, 'Bảo quản', 'Vệ sinh định kỳ, tránh nơi ẩm.'),
(100, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ chơi điện tử trẻ em.'),
(100, 'Loại sản phẩm', 'Xe điện ô tô trẻ em điều khiển từ xa.'),
(100, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–6 tuổi.'),
(100, 'Chất liệu', 'Nhựa cao cấp kết hợp linh kiện điện tử an toàn.'),
(100, 'Công dụng', 'Giúp bé vui chơi, phát triển kỹ năng điều khiển và phản xạ.'),
(100, 'Tính năng', 'Có điều khiển từ xa cho phụ huynh, phát nhạc, đèn LED.'),
(100, 'Nguồn điện', 'Sử dụng pin sạc, thời gian sử dụng dài.'),
(100, 'Thiết kế', 'Thiết kế mô phỏng xe ô tô thật, sang trọng và bắt mắt.'),
(100, 'Hướng dẫn sử dụng', 'Sạc pin đầy trước khi sử dụng và điều khiển bằng remote hoặc tay lái.'),
(100, 'Bảo quản', 'Tránh nước và bảo quản nơi khô ráo.'),
(101, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ chơi điện tử an toàn cho trẻ em, đảm bảo chất lượng và độ bền cao.'),
(101, 'Loại sản phẩm', 'Xe điện ô tô trẻ em cao cấp mô phỏng kiểu dáng Lamborghini.'),
(101, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–6 tuổi.'),
(101, 'Tải trọng', 'Chịu tải tối đa khoảng 25–30kg.'),
(101, 'Chất liệu', 'Nhựa cao cấp kết hợp khung chịu lực chắc chắn, an toàn cho trẻ nhỏ.'),
(101, 'Công dụng', 'Giúp bé vui chơi giải trí, phát triển khả năng điều khiển và phản xạ.'),
(101, 'Tính năng', 'Có điều khiển từ xa cho phụ huynh, tích hợp nhạc, đèn LED và nhiều chế độ lái.'),
(101, 'Nguồn điện', 'Sử dụng pin sạc dung lượng cao, thời gian sử dụng kéo dài.'),
(101, 'Thiết kế', 'Thiết kế sang trọng, mô phỏng xe thể thao với màu sắc bắt mắt.'),
(101, 'Hướng dẫn sử dụng', 'Sạc pin đầy trước khi sử dụng, có thể điều khiển bằng remote hoặc cho bé tự lái.'),
(101, 'Bảo quản', 'Tránh nước và môi trường ẩm, vệ sinh định kỳ.'),
(102, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn đồ chơi vận động cho trẻ em.'),
(102, 'Loại sản phẩm', 'Xe scooter 3 bánh giúp bé vận động và phát triển thể chất.'),
(102, 'Độ tuổi', 'Phù hợp cho trẻ từ 3–8 tuổi.'),
(102, 'Tải trọng', 'Chịu tải tối đa khoảng 40–50kg.'),
(102, 'Chất liệu', 'Khung hợp kim chắc chắn, bánh xe cao su bền và êm.'),
(102, 'Công dụng', 'Giúp bé rèn luyện khả năng giữ thăng bằng và tăng cường vận động.'),
(102, 'Tính năng', 'Thiết kế 3 bánh giúp tăng độ ổn định, dễ điều khiển.'),
(102, 'Thiết kế', 'Màu sắc tươi sáng, tay lái có thể điều chỉnh độ cao.'),
(102, 'An toàn', 'Bề mặt chống trượt, bánh xe bám đường tốt.'),
(102, 'Hướng dẫn sử dụng', 'Đứng lên xe, giữ thăng bằng và dùng chân đẩy để di chuyển.'),
(102, 'Bảo quản', 'Tránh nước và kiểm tra định kỳ các bộ phận.'),
(103, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn an toàn dành cho xe trẻ em.'),
(103, 'Loại sản phẩm', 'Xe đạp 3 bánh dành cho trẻ nhỏ tập đạp.'),
(103, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–5 tuổi.'),
(103, 'Tải trọng', 'Chịu tải tối đa khoảng 25kg.'),
(103, 'Chất liệu', 'Khung thép chắc chắn kết hợp nhựa cao cấp.'),
(103, 'Công dụng', 'Giúp bé tập đạp xe, phát triển cơ chân và khả năng phối hợp.'),
(103, 'Tính năng', 'Có giỏ đựng đồ phía trước, bàn đạp dễ sử dụng.'),
(103, 'Thiết kế', 'Thiết kế 3 bánh cân bằng, an toàn cho trẻ mới tập.'),
(103, 'An toàn', 'Bánh xe chống trượt, khung chắc chắn.'),
(103, 'Hướng dẫn sử dụng', 'Cho bé ngồi lên xe và tập đạp dưới sự giám sát của người lớn.'),
(103, 'Bảo quản', 'Giữ nơi khô ráo, tránh mưa nắng.'),
(104, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn xe đẩy trẻ em quốc tế, đảm bảo độ an toàn cao.'),
(104, 'Loại sản phẩm', 'Xe đẩy du lịch gấp gọn tiện lợi.'),
(104, 'Độ tuổi', 'Phù hợp cho trẻ từ sơ sinh đến 3 tuổi.'),
(104, 'Tải trọng', 'Chịu tải tối đa khoảng 15–20kg.'),
(104, 'Chất liệu', 'Khung nhôm nhẹ, vải cao cấp thoáng khí.'),
(104, 'Công dụng', 'Giúp bé di chuyển thoải mái khi đi chơi hoặc du lịch.'),
(104, 'Tính năng', 'Gấp gọn nhanh, dễ mang theo, có mái che chống nắng.'),
(104, 'Thiết kế', 'Thiết kế hiện đại, bánh xe linh hoạt dễ điều khiển.'),
(104, 'An toàn', 'Có dây đai an toàn và hệ thống phanh chắc chắn.'),
(104, 'Hướng dẫn sử dụng', 'Mở xe, cố định khóa và đặt bé vào sử dụng.'),
(104, 'Bảo quản', 'Giữ sạch và tránh nơi ẩm.'),
(105, 'Xuất xứ', 'Sản phẩm được sản xuất theo tiêu chuẩn đồ chơi vận động cho trẻ em.'),
(105, 'Loại sản phẩm', 'Xe cân bằng không bàn đạp giúp bé tập giữ thăng bằng.'),
(105, 'Độ tuổi', 'Phù hợp cho trẻ từ 2–5 tuổi.'),
(105, 'Tải trọng', 'Chịu tải tối đa khoảng 30kg.'),
(105, 'Chất liệu', 'Khung thép hoặc hợp kim nhẹ, bánh xe cao su bền.'),
(105, 'Công dụng', 'Giúp bé phát triển khả năng giữ thăng bằng trước khi tập xe đạp.'),
(105, 'Tính năng', 'Không có bàn đạp, bé dùng chân để đẩy và giữ thăng bằng.'),
(105, 'Thiết kế', 'Thiết kế nhỏ gọn, dễ sử dụng và di chuyển.'),
(105, 'An toàn', 'Khung chắc chắn, tay lái giới hạn góc quay để tránh té ngã.'),
(105, 'Hướng dẫn sử dụng', 'Cho bé ngồi và dùng chân đẩy để di chuyển.'),
(105, 'Bảo quản', 'Tránh nước và kiểm tra định kỳ.');
