INSERT INTO reviews (userId, productId, orderId, rating, comment) VALUES
(2,10,1,5,'Mùi hương nhẹ nhàng, không gây khó chịu. Dùng cho bé thấy da mềm hơn hẳn, không bị khô sau khi tắm, khá yên tâm khi sử dụng lâu dài.'),
(2,25,1,4,'Dùng khá tiện, vệ sinh sạch sẽ và an toàn. Chỉ có điều giá hơi cao so với mấy loại thông thường nhưng chất lượng ổn.'),
(3,5,2,5,'Dễ pha, mịn và thơm nhẹ, bé ăn hợp tác hơn. Sau một thời gian thấy tiêu hóa ổn định hơn nên khá hài lòng.'),
(3,30,2,4,'Đo nhanh, tiện khi bé ngủ không cần chạm nhiều. Đôi lúc phải đo lại để chính xác hơn nhưng nhìn chung vẫn ổn.'),
(4,12,3,4,'Thấm hút tốt, mặc qua đêm không bị tràn. Bé vận động thoải mái, không bị hằn da nhiều.'),
(6,8,5,4,'Khung chắc chắn, đẩy nhẹ và dễ điều khiển. Gấp lại cũng khá gọn nên mang đi ra ngoài tiện.'),
(6,40,5,3,'Thiết kế đẹp, bé chơi cũng thích nhưng có vài chi tiết nhỏ nên phải để ý khi bé sử dụng.'),
(2,15,7,3,'Mềm và dễ chịu khi dùng nhưng khả năng thấm hút ở mức trung bình, cần thay thường xuyên hơn một chút.'),
(5,70,19,5,'Dùng thấy rất ổn, bé hấp thu tốt và không bị táo bón. Sau một thời gian thấy phát triển đều nên khá yên tâm.'),
(5,15,19,4,'Mềm và thoáng, bé mặc không bị hăm. Tuy nhiên phải thay đều để giữ khô ráo.'),
(1,12,21,4,'Khả năng thấm hút tốt, dùng qua đêm vẫn ổn. Form hơi rộng nhẹ nhưng không ảnh hưởng nhiều.'),
(3,3,23,4,'Bé uống hợp, không bị đầy bụng. Vị dễ uống nên bé chịu hợp tác hơn.'),
(4,25,24,4,'Dùng tiện và sạch, dễ mang theo. Đóng gói chắc chắn nên khá yên tâm.'),
(4,35,24,4,'Hoạt động ổn định, dễ sử dụng. Phù hợp dùng trong gia đình hàng ngày.'),
(5,8,25,4,'Đẩy nhẹ, dễ điều khiển, đi ra ngoài khá tiện. Gấp lại cũng không chiếm nhiều diện tích.'),
(5,18,25,3,'Dùng được nhưng chưa thấy khác biệt nhiều. Hiệu quả ở mức trung bình.'),
(1,22,27,4,'Dùng ngoài trời khá ổn, không bị rít hay khó chịu. Thấm nhanh và không gây nhờn.'),
(1,55,27,4,'Làm nóng nhanh, tiện lợi khi cần sử dụng gấp. Thiết kế đơn giản, dễ dùng.'),
(2,65,28,4,'Sát khuẩn tốt, dùng nhanh gọn khi ra ngoài. Không gây khô da nhiều như mình nghĩ.'),
(2,75,28,4,'Bé uống hợp, vị dễ chịu. Sau một thời gian thấy cải thiện rõ rệt.'),
(3,33,29,5,'Rất tiện lợi, tiết kiệm thời gian đáng kể. Hoạt động ổn định, dễ sử dụng.'),
(3,44,29,4,'Thiết kế dễ nhìn, giúp bé học dễ hơn. Dùng lâu vẫn thấy ổn định.'),
(5,14,31,4,'Mềm mại, không gây kích ứng da. Dùng hàng ngày khá yên tâm.'),
(6,28,32,4,'Hút khá nhẹ nhàng, bé không bị khó chịu. Dễ vệ sinh sau khi sử dụng.'),
(6,38,32,4,'Lắp ráp đơn giản, chơi khá thú vị. Bé thích nên cũng thấy đáng tiền.'),
(1,60,33,4,'Dùng ổn, không bị kích ứng da. Phù hợp dùng thường xuyên.'),
(1,70,33,5,'Hiệu quả rõ rệt sau một thời gian sử dụng. Rất hài lòng với chất lượng.'),
(2,90,34,5,'Thiết kế đẹp, bé rất thích. Chạy ổn định và dễ điều khiển.'),
(2,100,34,4,'Chắc chắn, an toàn khi sử dụng. Phù hợp cho bé chơi trong nhà hoặc ngoài trời.'),
(5,70,19,5,'Sau một thời gian sử dụng thấy hiệu quả khá rõ rệt, bé hấp thu tốt và không gặp vấn đề về tiêu hóa. Chất lượng ổn định nên mình khá yên tâm khi dùng lâu dài.'),
(5,15,19,4,'Chất liệu mềm mại, dùng khá thoải mái và không gây kích ứng. Tuy nhiên vẫn cần thay thường xuyên để giữ khô ráo tốt hơn.'),
(1,12,21,4,'Khả năng thấm hút tốt, dùng qua đêm vẫn ổn. Bé vận động nhiều nhưng không bị khó chịu, nhìn chung khá hài lòng.'),
(3,3,23,4,'Bé dùng hợp, không bị đầy bụng hay khó tiêu. Vị dễ uống nên bé hợp tác hơn, sẽ tiếp tục sử dụng thêm.'),
(4,25,24,4,'Thiết kế tiện lợi, dễ sử dụng và mang theo. Dùng hàng ngày thấy khá ổn, đảm bảo vệ sinh tốt.'),
(4,35,24,4,'Hoạt động ổn định, dễ sử dụng ngay từ lần đầu. Phù hợp với nhu cầu sử dụng cơ bản trong gia đình.'),
(5,8,25,3,'Dùng được nhưng chưa thật sự nổi bật. Vẫn đáp ứng nhu cầu cơ bản nhưng nếu cải thiện thêm sẽ tốt hơn.'),
(5,18,25,4,'Kết cấu nhẹ, dễ sử dụng và không gây khó chịu. Sau khi dùng thấy khá ổn và phù hợp sử dụng lâu dài.'),
(1,22,27,4,'Dùng ngoài trời khá ổn, không gây cảm giác bí hay khó chịu. Thấm nhanh và không để lại cảm giác nhờn.'),
(1,55,27,4,'Làm nóng nhanh, thao tác đơn giản nên rất tiện khi cần sử dụng gấp. Thiết kế gọn gàng, dễ bảo quản.'),
(2,65,28,4,'Sử dụng nhanh gọn, phù hợp khi ra ngoài. Không gây khô da nhiều nên có thể dùng thường xuyên.'),
(2,75,28,4,'Dễ uống, vị khá nhẹ nên bé hợp tác tốt. Sau một thời gian sử dụng thấy cải thiện rõ rệt.'),
(3,33,29,4,'Sử dụng tiện lợi, giúp tiết kiệm thời gian đáng kể. Hoạt động ổn định và dễ làm quen.'),
(3,44,29,4,'Thiết kế trực quan, dễ hiểu nên bé tiếp cận nhanh. Dùng một thời gian vẫn thấy ổn định.'),
(5,14,31,4,'Mềm mại và không gây kích ứng da khi sử dụng. Phù hợp dùng hàng ngày nên khá yên tâm.'),
(6,28,32,4,'Hoạt động nhẹ nhàng, không gây khó chịu khi sử dụng. Dễ vệ sinh nên rất tiện lợi.'),
(6,38,32,4,'Lắp ráp đơn giản, bé chơi khá thích. Giúp bé vận động và giải trí tốt hơn.'),
(1,60,33,4,'Dùng khá ổn, không gây kích ứng hay khó chịu. Phù hợp sử dụng lâu dài trong sinh hoạt hàng ngày.'),
(1,70,33,4,'Hiệu quả khá rõ sau một thời gian sử dụng. Chất lượng ổn định nên có thể yên tâm dùng tiếp.');